{
  "verses": [
    {
      "n": 20,
      "column": "left",
      "text": "Jo Deewß irr to Gudri-\nbu winnam atnehmis/ un ne irr\ntam Saprachann padallijs.\n"
    },
    {
      "n": 21,
      "column": "left",
      "text": "Laikan/ kad tas aug-\nſcham uszettahs/ apſmeij wiꞥſch\nto Sirgu un winna Jahtneeku.\n"
    },
    {
      "n": 22,
      "column": "left",
      "text": "Warri tu Sirgam Speh-\nfu doht/ un winnam to Kaklu\nar Krehtim puschkocht?\n"
    },
    {
      "n": 23,
      "column": "left",
      "text": "Warri tu to beedeht ka\nweenu Siffeni/ kad tas ar Nah-\ntim krähz/ tad tas istruhzina.\n"
    },
    {
      "n": 24,
      "column": "left",
      "text": "Wiꞥſch zehrt dsilſti ar\nKahju/ un irr preezigß ar Speh-\nfu/ un iſeet tam Apbruxnotam\npretti.\n"
    },
    {
      "n": 25,
      "column": "left",
      "text": "Wiꞥſch apnehd to Bih-\njafchann/ un ne bailojahß/ un ne\ngreeschahß ta Sohbina pehz at-\npakat.\n"
    },
    {
      "n": 26,
      "column": "left",
      "text": "Kad tas Bultu-Maks\nſkann/ un arridsan tas leef-\nmains Aſmins un Schkehrs.\n"
    },
    {
      "n": 27,
      "column": "left",
      "text": "Tad tas raustahß/ trak-\nfo un uszehrt to Semmi/ un ne\nturrahß weena Weetâ/ kad\nTrummietes ſkann.\n"
    },
    {
      "n": 28,
      "column": "left",
      "text": "Kad tahß Trummietes\nſkann/ tad faſſa tas ht hi! un\nohſch to Rauschann no tahtenes/\nto Peel-Kungu Brehtschann un\nGawileſchann.\n"
    },
    {
      "n": 29,
      "column": "left",
      "text": "Arrig zaar tawu Padob-\nmu tas Wehja-Wañags ſcreen/\nun iſpleſch jawus Spahrnuß\nprett Deenas Widdu?\n"
    },
    {
      "n": 30,
      "column": "left",
      "text": "Woj tas Ehrglis us ta-\nwu Wahrdtu tik angsti ſcreen/ ka\n"
    },
    {
      "n": 31,
      "column": "right",
      "text": "Wiꞥſch dſihwo Akmix-\nKalnôß/ un paleek tur us aug-\nſteim Akmixeem/ un ſtiprah-\nWeetahm.\n"
    },
    {
      "n": 32,
      "column": "right",
      "text": "No turrenes dsenna-\nwiꞥſch pehz Barribas/ un wi-\nna Azzis flattahß no tahtenes.\n"
    },
    {
      "n": 33,
      "column": "right",
      "text": "Ir winna Behrni dse-\nAffini/ un fur Maitas irr/ tu-\nirr wiꞥſch.\n"
    },
    {
      "n": 34,
      "column": "right",
      "text": "Un tas KUNGß atbi-\ndeja Ijabam/ un fazzija:\n"
    },
    {
      "n": 35,
      "column": "right",
      "text": "Neggi tas/ kas ar t\nWiſſuwarreno barrahß/ win-\npanahzis/ kas Deewu pelt/ n\nbij tam atbildeht?\n"
    },
    {
      "n": 36,
      "column": "right",
      "text": "Bet Ijabß atbildeja tan\nKUNGAM/ un fazzija:\n"
    },
    {
      "n": 37,
      "column": "right",
      "text": "Redſi/ es etnu netikli-\nbtjis/ ko tad es tew atbildeschu\nes liſſchu fawu Rohku us faw-\nMutti.\n"
    },
    {
      "n": 38,
      "column": "right",
      "text": "Es eſnu weenkahrt run-\nnajß/ bet es ne atbildeschu ohtr-\nReiſi/ es to ne gribbu; wair\ndarriht.\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "N tas KUNGß atbi-\ndeja Ijabam is weena-\nWehtras/ un fazzija:\n"
    },
    {
      "n": 2,
      "column": "right",
      "text": "Apjoſs jelle ka ween-\nWihrs tawus Gurnus/ tad e-\ntew gribbu waizaht/ un tu ma-\nzi mann.\n"
    },
    {
      "n": 3,
      "column": "right",
      "text": "Bij tew mannu Teefu ie-\nnihz\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
